SpectremDirector.Entities={records={}}
local E=SpectremDirector.Entities
local function load(model) local hash=joaat(model);if not IsModelInCdimage(hash) then return nil end;RequestModel(hash);while not HasModelLoaded(hash) do Wait(0) end;return hash end
function E.spawn(kind,data) if not SpectremDirector.Types[kind] then return nil,'Invalid entity type' end;local max=Config.limits[kind..'s'];local count=0;for _ in pairs(E.records) do count=count+1 end;if count>=max then return nil,'Entity limit reached' end;local hash=load(data.model);if not hash then return nil,'Unknown model' end;local pos=data.position and SpectremDirector.Util.vector(data.position) or GetEntityCoords(PlayerPedId())+GetEntityForwardVector(PlayerPedId())*2;local entity=kind=='actor' and CreatePed(4,hash,pos.x,pos.y,pos.z,data.heading or 0,false,true) or kind=='vehicle' and CreateVehicle(hash,pos.x,pos.y,pos.z,data.heading or 0,false,true) or CreateObject(hash,pos.x,pos.y,pos.z,false,false,false);SetEntityAsMissionEntity(entity,true,true);local id=kind..':'..entity;E.records[id]={id=id,handle=entity,type=kind,model=data.model,name=SpectremDirector.Util.name(data.name,kind)};return E.records[id] end
function E.remove(id) local item=E.records[id];if item and DoesEntityExist(item.handle) then DeleteEntity(item.handle) end;E.records[id]=nil end
function E.serialize() local out={};for _,item in pairs(E.records) do if DoesEntityExist(item.handle) then out[#out+1]={type=item.type,model=item.model,name=item.name,position=SpectremDirector.Util.table(GetEntityCoords(item.handle)),heading=GetEntityHeading(item.handle)} end end;return out end
function E.restore(records) for id in pairs(E.records) do E.remove(id) end;for _,item in ipairs(records or {}) do E.spawn(item.type,item) end end
